-- Bitmap generated from MTA 1.6 editor_gui/client/browser/objects.xml.
-- Calling engineGetModelNameFromID with an invalid ID logs a warning, so AMX
-- validates GTA:SA object IDs without probing the engine.
local validObjectModelBitmap = [[]]

function mrpIsValidObjectModel(model)
    model = tonumber(model)
    if not model or model < 0 or model % 1 ~= 0 then
        return false
    end

    local byteOffset = math.floor(model / 8) * 2 + 1
    if byteOffset + 1 > #validObjectModelBitmap then
        return false
    end

    local byteValue = tonumber(validObjectModelBitmap:sub(byteOffset, byteOffset + 1), 16)
    local bitValue = 2 ^ (model % 8)
    return byteValue and byteValue % (bitValue * 2) >= bitValue or false
end
